INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic, created_at, updated_at) VALUES
('a4d14fad-cdae-53b7-bf94-107898e1a6b1', 'fdc38a93-cb6b-4e1c-8558-4c099ccd7a28', 'Many people want to travel to ___ to see the Great Wall.', '許多人想去___看長城。', 'China', 'Japan', 'France', 'Brazil', 'China 為專有名詞，指中國。', '看到 Great Wall (長城) 就聯想到 China (中國)。', '2026-07-07 03:47:17', '2026-07-07 03:47:17'),
('c47a56cd-9d80-5b49-ace7-4c30b6af4aa9', 'd76b193f-34e1-49bf-847c-4123bfc01129', 'I want to learn ___ to travel to the UK.', '我想學英語以便去英國旅遊。', 'English', 'French', 'German', 'Spanish', 'English 在此作為名詞，指「英語」。', '看到 UK (英國) 就聯想到 English (英語/英國的)。', '2026-07-07 03:55:07', '2026-07-07 03:55:07'),
('9f55427c-3ee0-5402-82bc-a26ec7d793e9', 'b8ea8171-0335-404c-803d-89e5b46a3edb', 'The prosecutor decided to ___ the suspect of stealing the valuable jewelry from the museum.', '檢察官決定指控該嫌犯從博物館偷竊珍貴珠寶。', 'accuse', 'praise', 'protect', 'forgive', 'accuse 源自拉丁語 ad- (向著) + causa (原因/理由)，字面意義為「針對某個原因」，引申為「指控」。', 'accuse (指控) → 想像法官指著嫌犯說：''A cue!'' (一個提示/信號)，這就是指控犯罪的信號。', '2026-07-06 17:04:32', '2026-07-06 17:04:32'),
('2813fe28-3716-53b6-a4c7-eee278ca733d', 'accd4209-582e-4cb9-b50d-d2ec9b9f1d87', 'The committee was formed to ___ the funds provided by the government.', '成立該委員會是為了管理政府提供的資金。', 'administrate', 'decorate', 'investigate', 'communicate', '字根 admin 表示管理，字尾 -ate 為動詞字尾。', '將 admin (管理員) 與 -ate (動詞字尾) 結合：admin + ate → administrate (管理)。', '2026-07-06 17:48:55', '2026-07-06 17:48:55'),
('47d6f4c0-555c-5194-9efc-4dcd50208989', '9c67db0c-6e67-468f-b55f-bdda86a2bab1', 'The museum offers free ___ to all students who present a valid ID card.', '這間博物館為所有出示有效證件的學生提供免費入場。', 'admission', 'attention', 'tradition', 'condition', 'ad (朝向) + miss (送) → 送進去 → 進入許可、入場費。', '想像你要被「送 (miss)」進去某個地方，需要得到「准許 (admission)」。', '2026-07-06 17:54:40', '2026-07-06 17:54:40'),
('4a4fb3d0-291b-515c-892e-f1d2c0dd7f2d', '4da579a0-1be9-4308-be94-cc42781f0af0', 'Due to the sudden increase in gas prices, many families can no longer ___ to drive long distances every weekend.', '由於汽油價格突然上漲，許多家庭無法再負擔每週末長途開車的費用。', 'afford', 'refuse', 'expect', 'prepare', 'af- (朝向) + ford (提供) → 提供 → 能夠負擔。', '看到 expensive 或 gas prices 等金錢相關單字時，聯想 afford (買得起)。', '2026-07-06 18:41:06', '2026-07-06 18:41:06'),
('54c7d75e-b6f4-59aa-b070-13b791adefa1', 'a763d127-b9e9-4353-a759-23505e80ecba', 'A mysterious shadow began to ___ on the wall as the candle flickered.', '隨著燭光搖曳，牆上開始出現一個神秘的影子。', 'appear', 'vanish', 'wander', 'belong', 'ap (向著) + pear (看/顯示)', 'ap (向著) + pear (看) → 向著你看 → 出現', '2026-07-06 22:54:46', '2026-07-06 22:54:46'),
('95c9f472-e6fb-57be-8f35-4f831e4b857d', '9e87aeb1-33ac-4530-bb13-b40fb7a0a0a7', 'There are many big trees ___ the house.', '房子周圍有很多大樹。', 'around', 'under', 'between', 'behind', 'a (在/向) + round (圓形) → 繞著圓形的範圍。', 'round 是圓形，around 就是繞著圓形走 → 周圍、附近。', '2026-07-06 14:49:28', '2026-07-06 14:49:28'),
('5a0cbabc-707d-500e-8172-dae6b1907095', '99a89a9e-8a2f-4fbf-9463-fd6f9d2ee5bb', 'The teenager was easily led ___ by his new group of friends.', '這位青少年很容易被他的新朋友們誤導。', 'astray', 'ahead', 'aside', 'abroad', 'a- (表示在某種狀態) + stray (迷路、流浪) → 誤入歧途地。', 'stray 有流浪的意思，加上 a- 前綴表示「處於迷失或走錯路的方向」→ astray (誤入歧途地)。', '2026-07-07 01:38:26', '2026-07-07 01:38:26'),
('b7153610-6a1c-52b2-bb2f-3eed28c45431', 'd7de2d9b-d2d8-4a8a-91f8-3b03438cac80', 'The ___ is the smallest unit of an element that retains its chemical properties.', '原子是保留其化學性質的元素最小單位。', 'atom', 'cell', 'star', 'cloud', '源自希臘語 atomos，意為「不可分割的」。', '想像一個小到無法被切割的東西 → 原子。', '2026-07-07 01:54:14', '2026-07-07 01:54:14'),
('2d4bbac9-c138-5013-b664-c36be948ec41', 'b7ced09e-9378-43ca-a3b6-54b97a3cea97', 'We must ___ the decision of the committee before we can proceed with the project.', '在我們繼續進行這項計畫之前，我們必須等候委員會的決定。', 'await', 'ignore', 'refuse', 'create', 'a- 表示「向著」或「在...之中」，加上 wait (等待) → 期待、等候。', 'a- (向著) + wait (等待) → 專心向著某事等待 → 期待、等候。', '2026-07-07 04:11:46', '2026-07-07 04:11:46'),
('c25ae7da-de4b-5c15-b993-8ad84f4e3e25', '21c1ad12-f839-492b-a8e3-8bb8d03cef06', 'You should eat healthy food to keep your ___ strong.', '你應該吃健康的食物來保持你的身體強壯。', 'body', 'mind', 'face', 'hand', '名詞，指人的身體或軀幹。', 'Body → 保底 → 保養你的身體。', '2026-07-07 04:56:24', '2026-07-07 04:56:24'),
('84d6ee4a-639c-5e97-9f12-6c4100dfc949', '2955f655-727c-471f-9782-fc6d5bacb0ac', 'Please sit on that wooden ___ during the class.', '請在課堂上坐在那張木椅上。', 'chair', 'table', 'window', 'floor', 'chair 作為名詞時，意思是指「椅子」。', '想像坐在椅子 (chair) 上的人通常就是會議的主席。', '2026-07-07 03:03:50', '2026-07-07 03:03:50'),
('f0c78b1c-c119-5e3d-8058-f89b4d302465', '9de5da41-7c83-4fc6-9cbd-f289a441c4c2', '___ in my class is very kind.', '我班上的每個人都很親切。', 'Everyone', 'Everything', 'Someone', 'Nothing', 'every (每個) + one (一個) → 每個人', '將 every (每個) 與 one (一個) 結合，表示每一個人。', '2026-07-07 04:34:01', '2026-07-07 04:34:01'),
('604887eb-ce7d-5f7e-911f-e60151328469', 'f8dc4363-c562-4ebc-9447-362271fe2609', 'He made a bad ___ for being late to class.', '他為遲到上課找了一個很爛的藉口。', 'excuse', 'mistake', 'dream', 'prize', 'ex (向外) + cuse (理由) → 找理由向外推卸 → 藉口。', 'ex (向外) + cuse (理由) → 把理由說向外 → 藉口。', '2026-07-07 05:11:35', '2026-07-07 05:11:35'),
('bdae5cff-4d07-55f2-a426-d45b7e10e0d5', 'c06ad5b8-1e6c-4f00-8470-7f8a5418e1cc', 'Please turn ___ the light; it is too dark.', '請把燈打開；這裡太暗了。', 'on', 'up', 'out', 'in', '副詞，表示開啟（電器或燈）的狀態。', '開關切換到開啟狀態時，就是 on。', '2026-07-05 11:51:15', '2026-07-05 11:51:15'),
('273efa48-2366-50c8-b4db-2ed1f9e26bd1', '9a8e0f21-a05c-451e-bdbb-33b7687046a9', '___ must be quiet in the library.', '我們在圖書館必須保持安靜。', 'We', 'They', 'He', 'You', '第一人稱複數代名詞', '指代說話者與其他人的組合', '2026-07-06 10:45:59', '2026-07-06 10:45:59');
